// NEGATIVE CONTROL (must FAIL): identical to the target plus one share-
// recombining register (leak0 <= aout[0]^aout[1]). MATCHI must flag the
// gate sensitive in multiple shares (glitch leakage).
// Constant-product swap program over the verified masked units (structural
// copies): denom=ri+x (ADD), num=ro*x (MUL), aout=num/denom (DIV), ok =
// (aout>=mo) (borrow-out compare), nro=ro-aout (SUB). 3578 assumed-OPINI
// gadget leaves (1276 mul u_mpp_*/u_msc_*/u_mpx_*/u_mg_*/u_mt_*, 510 denom-add
// u_ag_*/u_at_*, 770 div u_dg_*/u_dt_*/u_dm_*, 512 compare u_cg_*/u_ct_*,
// 510 reserve-sub u_sg_*/u_st_*), each with a DEDICATED r[k]/s[k] random bit
// (disjoint per-stage slices). Every XOR/NOT/shift/hand-off is strictly
// share-local; control (counter, strobes, FSMs) is public and data-independent.
// Dense sharing layout (share index fastest): port[2i]=share0, port[2i+1]=share1.
// Schedule: load @0; mul [1,2048], prod captured @2572; denom captured @524;
// div go @2576, iteration i occupies [2576+1+528i, 2576+528(i+1)], Q/R stable @137745;
// ok/nro captured @138269; outputs valid [138270,138275]; global clr @138275;
// randoms fresh [0,138807].
(* matchi_prop = "PINI", matchi_strat = "composite_top", matchi_arch = "loopy", matchi_shares = 2 *)
module dexloop256_recomb (clk, rst, tx_go, we, waddr, raddr, wdata, x, mo,
                r, s, aout, nri, nro, ok, rdata, leak_o);
(* matchi_type = "clock" *)   input clk;
(* matchi_type = "control" *) input rst;
(* matchi_type = "control" *) input tx_go;
(* matchi_type = "control" *) input we;
(* matchi_type = "control" *) input [1:0] waddr;
(* matchi_type = "control" *) input [1:0] raddr;
(* matchi_type = "sharings_dense", matchi_active = "in_act" *) input [511:0] x;
(* matchi_type = "sharings_dense", matchi_active = "a_act" *) input [511:0] wdata;
(* matchi_type = "sharings_dense", matchi_active = "st_out_act" *) output [511:0] rdata;
(* matchi_type = "sharings_dense", matchi_active = "in_act" *) input [511:0] mo;
(* matchi_type = "random", matchi_active = "r_act" *) input [3577:0] r;
(* matchi_type = "random", matchi_active = "s_act" *) input [3577:0] s;
(* matchi_type = "sharings_dense", matchi_active = "out_act" *) output [511:0] aout;
(* matchi_type = "sharings_dense", matchi_active = "out_act" *) output [511:0] nri;
(* matchi_type = "sharings_dense", matchi_active = "out_act" *) output [511:0] nro;
(* matchi_type = "sharing", matchi_active = "out_act" *) output [1:0] ok;
(* matchi_type = "sharing", matchi_active = "out_act" *) output [1:0] leak_o;


