// (persistent copies of storage words — sticky sensitivity like the pad;
// no clr, mirroring the storage lanes themselves)
reg [255:0] rri0, rri1, rro0, rro1;
// both lanes captured at the SAME edge (the store16x4 paging rule)
always @(posedge clk) begin
    if (rst) begin
        rri0 <= 0; rri1 <= 0; rro0 <= 0; rro1 <= 0;
    end else begin
        if (pcnt == 3'd2) begin rri0 <= rreg0; rri1 <= rreg1; end   // slot0
        if (pcnt == 3'd3) begin rro0 <= rreg0; rro1 <= rreg1; end   // slot1
    end
end
wire go = (pcnt == 3'd4);   // internal swap-go strobe

// ---- global cycle counter (public control; counts 1.. from go, saturates —
// the div256 window pattern) + per-stage strobes at fixed counts ----
reg [18:0] cnt;
always @(posedge clk) begin
    if (rst)                       cnt <= 19'd0;
    else if (go)                   cnt <= 19'd1;
    else if (cnt != 19'd0 && cnt != 19'd138810) cnt <= cnt + 19'd1;
end
