[2], x[0]};
        m_bb1 <= {x[511], x[509], x[507], x[505], x[503], x[501], x[499], x[497], x[495], x[493], x[491], x[489], x[487], x[485], x[483], x[481], x[479], x[477], x[475], x[473], x[471], x[469], x[467], x[465], x[463], x[461], x[459], x[457], x[455], x[453], x[451], x[449], x[447], x[445], x[443], x[441], x[439], x[437], x[435], x[433], x[431], x[429], x[427], x[425], x[423], x[421], x[419], x[417], x[415], x[413], x[411], x[409], x[407], x[405], x[403], x[401], x[399], x[397], x[395], x[393], x[391], x[389], x[387], x[385], x[383], x[381], x[379], x[377], x[375], x[373], x[371], x[369], x[367], x[365], x[363], x[361], x[359], x[357], x[355], x[353], x[351], x[349], x[347], x[345], x[343], x[341], x[339], x[337], x[335], x[333], x[331], x[329], x[327], x[325], x[323], x[321], x[319], x[317], x[315], x[313], x[311], x[309], x[307], x[305], x[303], x[301], x[299], x[297], x[295], x[293], x[291], x[289], x[287], x[285], x[283], x[281], x[279], x[277], x[275], x[273], x[271], x[269], x[267], x[265], x[263], x[261], x[259], x[257], x[255], x[253], x[251], x[249], x[247], x[245], x[243], x[241], x[239], x[237], x[235], x[233], x[231], x[229], x[227], x[225], x[223], x[221], x[219], x[217], x[215], x[213], x[211], x[209], x[207], x[205], x[203], x[201], x[199], x[197], x[195], x[193], x[191], x[189], x[187], x[185], x[183], x[181], x[179], x[177], x[175], x[173], x[171], x[169], x[167], x[165], x[163], x[161], x[159], x[157], x[155], x[153], x[151], x[149], x[147], x[145], x[143], x[141], x[139], x[137], x[135], x[133], x[131], x[129], x[127], x[125], x[123], x[121], x[119], x[117], x[115], x[113], x[111], x[109], x[107], x[105], x[103], x[101], x[99], x[97], x[95], x[93], x[91], x[89], x[87], x[85], x[83], x[81], x[79], x[77], x[75], x[73], x[71], x[69], x[67], x[65], x[63], x[61], x[59], x[57], x[55], x[53], x[51], x[49], x[47], x[45], x[43], x[41], x[39], x[37], x[35], x[33], x[31], x[29], x[27], x[25], x[23], x[21], x[19], x[17], x[15], x[13], x[11], x[9], x[7], x[5], x