reg [255:0] d_xm_d0, d_xm_d1;  // ina of u_dm_*  (inb = d_coutr)
always @(posedge clk) begin
    d_Rsh_d0 <= d_Rsh0;                        d_Rsh_d1 <= d_Rsh1;
    d_xm_d0  <= d_Rsh0[255:0] ^ d_Treg0;     d_xm_d1  <= d_Rsh1[255:0] ^ d_Treg1;
end

// ==================== stage C: CMP ok = (aout >= mo), SUB nro = ro - aout ====================
// cmp: aout - mo borrow-out. b := mo complemented share-locally (sub=1),
// a := Q via balance register. subro: b := ~Q (share 0), a := hro_d.
reg [255:0] d_Q_d0, d_Q_d1;    // ina of u_cg_* (inb = ~hmo0/hmo1)
reg [255:0] hro_d0, hro_d1;    // ina of u_sg_* (inb = ~d_Q0/d_Q1)
always @(posedge clk) begin
    d_Q_d0 <= d_Q0;  d_Q_d1 <= d_Q1;
    hro_d0 <= hro0;  hro_d1 <= hro1;
end
(* keep *) wire c_coutw0, c_coutw1;           // compare borrow-out wires
(* keep *) wire [255:0] s_sum0, s_sum1;     // reserve-sub sum wires
reg ok0, ok1;                                 // captured ok = (aout >= mo)
reg [255:0] nror0, nror1;                   // captured nro = ro - aout
always @(posedge clk) begin
    if (rst || clr) begin ok0 <= 0; ok1 <= 0; nror0 <= 0; nror1 <= 0; end
    else if (ok_cap) begin
        ok0 <= c_coutw0; ok1 <= c_coutw1;
        nror0 <= s_sum0; nror1 <= s_sum1;
    end
end

// ---- outputs: dense re-pack of the result registers (share-local wiring) ----
assign ok = {ok1, ok0};


// ---- WRITEBACK strobes (swap counter domain; strictly before clr) ----
// slot0 <= D (nri = newReserveIn) at OK_CAP+2; slot1 <= nror (nro) at OK_CAP+3.
wire wb1 = (cnt == 19'd138271);
wire wb2 = (cnt == 19'd138272);
wire eff_we = we || wb1 || wb2;
wire [1:0] eff_waddr = wb1 ? 2'd0 : (wb2 ? 2'd1 : waddr);
// per-lane write-value mux: lane k mixes only share-k values (public selects)
wire [255:0] wv0 = wb1 ? D0 : (wb2 ? nror0 : wd0);
wire [255:0] wv1 = wb1 ? D1 : (wb2 ? nror1 : wd1);

// ---- lane 0 writes ----
always @(posedge clk) begin
    if (eff_we && eff_waddr == 2'd0) m0_0 <= wv0;
    if (eff_we && eff_waddr == 2'd1) m0_1 <= wv0;
    if (eff_we && eff_waddr == 2'd2) m0_2 <= wv0;
    if (eff_we && eff_waddr == 2'd3) m0_3 <= wv0;
end
// ---- lane 1 writes ----
always @(posedge clk) begin
    if (eff_we && eff_waddr == 2'd0) m1_0 <= wv1;
    if (eff_we && eff_waddr == 2'd1) m1_1 <= wv1;
    if (eff_we && eff_waddr == 2'd2) m1_2 <= wv1;
    if (eff_we && eff_waddr == 2'd3) m1_3 <= wv1;
